    @Test
    fun testSubMillisecondRounding() {
        // Duration with sub-millisecond components should round up
        val duration = 998.milliseconds + 902752.nanoseconds  // 998.902752ms
        val result = duration.toDelayMillis()
        assertEquals(999L, result, "998.902752ms should round up to 999ms")
    }

    @Test  
    fun testExactMilliseconds() {
        // Exact milliseconds should not round up
        val duration = 1000.milliseconds
        val result = duration.toDelayMillis()
        assertEquals(1000L, result, "1000ms should stay 1000ms")
    }

    @Test
    fun testSubMillisecondOnly() {
        // Duration with only sub-millisecond components should round up to 1ms
        val duration = 500.nanoseconds
        val result = duration.toDelayMillis()  
        assertEquals(1L, result, "500ns should round up to 1ms")
    }

    @Test
    fun testOneNanosecond() {
        // Exactly 1 nanosecond should round up to 1ms  
        val duration = 1.nanoseconds
        val result = duration.toDelayMillis()
        assertEquals(1L, result, "1ns should round up to 1ms")
    }

    @Test
    fun testZeroDuration() {
        // Zero duration should return 0
        val duration = Duration.ZERO
        val result = duration.toDelayMillis()
        assertEquals(0L, result, "Zero duration should return 0ms")
    }

    @Test  
    fun testNegativeDuration() {
        // Negative duration should return 0
        val duration = (-100).milliseconds
        val result = duration.toDelayMillis()
        assertEquals(0L, result, "Negative duration should return 0ms")
    }

    @Test
    fun testLargeSubMillisecondComponent() {
        // 0.999999ms should round up to 1ms
        val duration = 999999.nanoseconds  // 0.999999ms
        val result = duration.toDelayMillis()
        assertEquals(1L, result, "0.999999ms should round up to 1ms")
    }

    @Test
    fun testMultipleMillisecondsWithSubComponent() {
        // 5.5ms should round up to 6ms
        val duration = 5.milliseconds + 500000.nanoseconds  // 5.5ms
        val result = duration.toDelayMillis()
        assertEquals(6L, result, "5.5ms should round up to 6ms")
    }

    @Test
    fun testEdgeCaseOneNanosecondBelowWholeMillisecond() {
        // 999.999999ms should round up to 1000ms
        val duration = 999.milliseconds + 999999.nanoseconds  // 999.999999ms
        val result = duration.toDelayMillis()  
        assertEquals(1000L, result, "999.999999ms should round up to 1000ms")
    }

    @Test
    fun testBackwardsCompatibilityWithExistingBehavior() {
        // Ensure existing behavior for exact milliseconds is preserved
        val testCases = listOf(
            1.milliseconds to 1L,
            10.milliseconds to 10L, 
            100.milliseconds to 100L,
            1000.milliseconds to 1000L,
            5000.milliseconds to 5000L
        )

        for ((duration, expected) in testCases) {
            val result = duration.toDelayMillis()
            assertEquals(expected, result, "$duration should convert to ${expected}ms")
        }
    }
}"}

